# 点火

使用`npm init`创建`package.json`，一路回车，当然你也可以配置相关信息，有兴趣可自己选择：



![img](https://user-gold-cdn.xitu.io/2019/4/26/16a5769708519d73?imageView2/0/w/1280/h/960/format/webp/ignore-error/1)

现在目录中自动生成一个`package.json`文件：



```
{
  "name": "exercise-cli",
  "version": "1.0.0",
  "description": "",
  "main": "index.js",
  "scripts": {
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "author": "",
  "license": "ISC"
}
复制代码
```

现在在`package.json`中添加字段`bin`，用来存放一个可执行的文件，我们此处的可执行文件就是index.js，因此配置如下：

```
"bin":{
    "exercise-cli":"./index.js"
},
复制代码
```

此时我们配置`exercise-cli`命令来执行`index.js`文件，需要在`index.js`文件头部添加`#!/usr/bin/env node`, 让系统自己去找node的执行程序。至于这玩意具体什么，百度出这么个[东西](https://zhidao.baidu.com/question/134547332.html)，可自行参考。

```
//index.js
#!/usr/bin/env node
console.log('谢邀，人在美国，刚下飞机。');
复制代码
```

然后在cmd输入`npn link`或`npm install -g`将当前项目安装到全局环境，这样就可以直接使用`exercise-cli`来运行文件了：



![img](https://user-gold-cdn.xitu.io/2019/4/26/16a5781734aec379?imageView2/0/w/1280/h/960/format/webp/ignore-error/1)

再学一点，在package.json的scripts字段里添加脚本名：



```
"scripts": {
    "test": "echo \"Error: no test specified\" && exit 1",
    "exercise":"exercise-cli"
 }
复制代码
```

命令行输入`npm run exercise`，同样输出了`index.js`里的内容，联想起`vue-cli`的`npm run dev`、`npm run build`等会不会若有所思呢？

# 起飞

有点样子了，接下来让我们看看它是如何生成项目模板的，一个思路是用一个templates文件夹保存项目模板，然后通过fs.mkdir()来创建项目目录，最后把文件从templates文件夹拷贝到项目中去。本地templates目录如下图所示：



![img](https://user-gold-cdn.xitu.io/2019/4/26/16a5792454a8c448?imageView2/0/w/1280/h/960/format/webp/ignore-error/1)



## 1.拷贝文件

模拟场景：将本地templates中的`vue.min.js`拷贝到新生成的项目模板中。在新生成的项目模板中新建public目录，该目录下新建js目录，将`vue.min.js`通过`copyTemplate()`方法从templates里拷贝到新建的js目录下面：

```
//index.js
#!/usr/bin/env node

var fs = require('fs');
var path = require('path');

// 复制文件
function copyTemplate (from, to) {
  from = path.join(__dirname, 'templates', from);
  console.log(from);
  write(to, fs.readFileSync(from, 'utf-8'))
}
function write (path, str, mode) {
  fs.writeFileSync(path, str)
}
// 新建目录
function mkdir (path, fn) {
  fs.mkdir(path, function (err) {
    fn && fn()
  })
}

var PATH = ".";
mkdir(PATH+'/public',function(){
	mkdir(PATH + '/public/js',function () {
		copyTemplate("/js/vue.min.js", PATH + '/public/js/vue.min.js');
	})
})

复制代码
```

用cmd打开任意文件夹输入`exercise-cli`,该文件夹下会`public\js\vue.min.js`:



![img](data:image/svg+xml;utf8,<?xml version="1.0"?><svg xmlns="http://www.w3.org/2000/svg" version="1.1" width="228" height="76"></svg>)



## 2.拷贝文件夹

我们学会了拷贝文件，那么如何拷贝整个文件夹呢，例如我想将templates下的整个js目录全部拷贝到新生成的项目模板中，又该如何？有需求就有方案，我们可以遍历整个文件夹，对遍历到的path进行判断，如果是文件则直接拷贝，如果是文件夹则递归：

```
//index.js
// 复制目录
var copy=function(src,dst){
    let paths = fs.readdirSync(src); //同步读取当前目录(只能读取绝对路径，相对路径无法获取)
    paths.forEach(function(path){
        var _src=src+'/'+path;
        var _dst=dst+'/'+path;
        fs.stat(_src,function(err,stats){  //stats  该对象 包含文件属性
            if(err)throw err;
            if(stats.isFile()){ //如果是个文件则拷贝 
                let  readable=fs.createReadStream(_src);//创建读取流
                let  writable=fs.createWriteStream(_dst);//创建写入流
                readable.pipe(writable);
            }else if(stats.isDirectory()){ //是目录则 递归 
                checkDirectory(_src,_dst,copy);
            }
        });
    });
}
var checkDirectory=function(src,dst,callback){
    fs.access(dst, fs.constants.F_OK, (err) => {
        if(err){
            fs.mkdirSync(dst);
            callback(src,dst);
        }else{
            callback(src,dst);
        }
      });
};

mkdir(PATH+'/public',function(){
	mkdir(PATH + '/public/js',function () {
		checkDirectory('C:/Users/Administrator/Desktop/vue-3.0/nodeTest/exercise/templates/js',PATH+'/public/js',copy);
	})
})
复制代码
```

依然在找一个文件夹打开cmd输入`exercise-cli`,该文件夹下会生成public目录，该目录下面会生成templates下的整个js文件：



